const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { GraphQLObjectType, GraphQLSchema, GraphQLString, GraphQLInt, GraphQLList, GraphQLNonNull } = require('graphql');
const { Pool } = require('pg');
const depthLimit = require('graphql-depth-limit');
const { createComplexityLimitRule } = require('graphql-validation-complexity');

const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'blog_db',
  password: 'password',
  port: 5432,
});

const AuthorType = new GraphQLObjectType({
  name: 'Author',
  fields: {
    id: { type: GraphQLInt },
    name: { type: GraphQLString },
    email: { type: GraphQLString }
  }
});

const PostType = new GraphQLObjectType({
  name: 'Post',
  fields: {
    id: { type: GraphQLInt },
    title: { type: GraphQLString },
    content: { type: GraphQLString },
    author_id: { type: GraphQLInt },
    author: {
      type: AuthorType,
      resolve: async (parent) => {
        const result = await pool.query('SELECT * FROM authors WHERE id = $1', [parent.author_id]);
        return result.rows[0];
      }
    }
  }
});

const RootQuery = new GraphQLObjectType({
  name: 'RootQueryType',
  fields: {
    post: {
      type: PostType,
      args: { id: { type: new GraphQLNonNull(GraphQLInt) } },
      resolve: async (parent, args) => {
        const result = await pool.query('SELECT * FROM posts WHERE id = $1', [args.id]);
        return result.rows[0];
      }
    },
    posts: {
      type: new GraphQLList(PostType),
      args: {
        limit: { type: GraphQLInt, defaultValue: 10 }
      },
      resolve: async (parent, args) => {
        const limit = Math.min(args.limit, 100);
        const result = await pool.query('SELECT * FROM posts LIMIT $1', [limit]);
        return result.rows;
      }
    },
    author: {
      type: AuthorType,
      args: { id: { type: new GraphQLNonNull(GraphQLInt) } },
      resolve: async (parent, args) => {
        const result = await pool.query('SELECT * FROM authors WHERE id = $1', [args.id]);
        return result.rows[0];
      }
    }
  }
});

const schema = new GraphQLSchema({
  query: RootQuery
});

const app = express();

app.use('/graphql', graphqlHTTP({
  schema: schema,
  graphiql: true,
  validationRules: [
    depthLimit(5),
    createComplexityLimitRule(1000, {
      onCost: (cost) => {
        console.log('Query cost:', cost);
      }
    })
  ],
  customFormatErrorFn: (error) => ({
    message: error.message,
    locations: error.locations,
    path: error.path
  })
}));

const PORT = 4000;
app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}/graphql`);
});